var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_CAP","text":{"KOREA":"막아라! 해자를 뛰어넘는 녀석들을 집중적으로 노려!","JPN":"阻止しろ！　堀を飛び越えるやつらを集中的に狙え！","ENG":"Stop them! Focus on getting the ones that are jumping over the moat!","TWN":"攔住它們！集中攻擊那些越過護城河的傢伙！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_MAM","text":{"KOREA":"대형 마물 접근 중!","JPN":"大型の魔物が接近中！","ENG":"A large monster is approaching!","TWN":"大型怪物正在接近！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_CAP","text":{"KOREA":"1열 방책, 상승 전개!","JPN":"1列防柵、上昇展開！","ENG":"Raise the first row of the barricades!","TWN":"第一排防線，升起展開！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_CAP","text":{"KOREA":"지금이다! 놈들의 움직임이 멈춘 틈에 대형에게 집중 사격해!!!","JPN":"今だ！　やつらの動きが止まっている間に大型に集中射撃しろ！","ENG":"NOW! Focus fire on the large one while the others can't move!","TWN":"就是現在！趁它們停下時集火大型目標！！！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_MAM","text":{"KOREA":"대형 마물 격파!!","JPN":"大型の魔物を撃破！！","ENG":"The large monster has been felled!","TWN":"大型怪物擊破！！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_CAP","text":{"KOREA":"잘 하고 있어! 이대로 계속 하는 거다!","JPN":"よくやった！　このまま続けるんだ！","ENG":"We're doing great! Let's keep at it!","TWN":"幹得好！繼續保持！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_MAM","text":{"KOREA":"상공에 날개 마물 출현!","JPN":"上空に翼のある魔物が出現！","ENG":"Winged monsters have appeared in the sky!","TWN":"空中出現有翅膀的怪物！"},"stage":{"bg":"SKY","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_MAM","text":{"KOREA":"지상에서도 대형 다수가 한꺼번에 옵니다!","JPN":"地上からも大型が多数、一斉に迫ってきています！","ENG":"Multiple large monsters are charging toward us from the ground as well!","TWN":"地面上也有大量大型目標同時出現！"},"stage":{"bg":"ROOT_VILLAGE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOT_VILLAGE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"지금일세!","JPN":"今だ！","ENG":"NOW!","TWN":"就是現在！"},"stage":{"bg":"ROOT_VILLAGE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_CAP","text":{"KOREA":"지금이다! 아발론의 방벽을 가동해!","JPN":"今だ！　アバロンの防壁を稼働しろ！","ENG":"Activate the barrier of Avalon!","TWN":"就是現在！啟動阿瓦隆的屏障！"},"stage":{"bg":"ROOT_VILLAGE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_CAP","text":{"KOREA":"뛰어들던 녀석들이 날파리처럼 떨어져 나가는군요.","JPN":"飛び込んできたやつらがハエのように弾き飛んでますね。","ENG":"Look at them fall to the ground. Even the ones that were jumping.","TWN":"那些衝過來的傢伙像蒼蠅一樣掉下去了。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_CAP","text":{"KOREA":"고대 유물이라 제대로 작동하기만 바랐는데… 이정도로 강력한 성능일 줄이야.","JPN":"古代の遺物なのでちゃんと作動するか不安でしたが……これほど強力な性能を見せてくれるとは。","ENG":"I just hoped that this ancient relic would work properly... But I never imagined it would be this potent.","TWN":"我還擔心這件古代遺物能不能正常運作…沒想到性能竟然這麼強。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"우리들이 연구하는 것도, 결국 아발론 선조들의 기술이 원천일세.","JPN":"私たちが研究しているのも、結局はアバロン祖先の技術を元にしている。","ENG":"All of our research is ultimately based on the technology of the ancestors of Avalon.","TWN":"我們研究的東西，追根究柢也是阿瓦隆祖先的技術。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"성능은 의심할 필요가 없지.","JPN":"その性能は疑う余地もない。","ENG":"There is no need to doubt its strength.","TWN":"性能是毋庸置疑的。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_MAM","text":{"KOREA":"어엇?!","JPN":"ああっ！？","ENG":"What?!","TWN":"咦？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_MAM","text":{"KOREA":"땅이 흔들립니다…!","JPN":"地面が揺れています……！","ENG":"The ground is trembling...!","TWN":"地面在震動…！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_CAP","text":{"KOREA":"지진인가?","JPN":"地震か？","ENG":"Is it an earthquake?","TWN":"是地震嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"…지하일세! 아래를 조심하게!","JPN":"……地下だ！　下に注意しろ！","ENG":"...They are beneath us! Be careful of your feet!","TWN":"…是地下！小心下面！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L39_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_MAM","text":{"KOREA":"이럴 수가…! 역장을 피해서 땅을 파고 들어온다고…?!","JPN":"そんな……！　力場を避けて土の下を掘って来ただと……！？","ENG":"Unbelievable...! They dug a hole underground to avoid the stasis field...?!","TWN":"怎麼會…！竟然避開了力場，鑽進了地裡…？！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"놈들은 방벽의 중추를 노리는 걸세! 저게 파괴되면 차단막이 사라지고 말아!!","JPN":"やつらは防壁の中枢を狙っているのだ！　あれが破壊されれば遮断幕が消えてしまう！！","ENG":"The monsters are aiming for the barrier's center! The barrier will fall if they destroy it!!","TWN":"那些傢伙的目標是屏障的核心！如果那裡被破壞，屏障就會消失！！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_MAM","text":{"KOREA":"너무 빨라서 맞힐 수가 없습니다!","JPN":"早すぎて当てられません！","ENG":"They are too fast to hit, sir!","TWN":"太快了，沒辦法命中！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_CAP","text":{"KOREA":"비켜! 내가 몸으로라도 막겠다!!","JPN":"どけ！　私が体を張ってでも止める！！","ENG":"Get out of the way! I'll stop them myself!!","TWN":"閃開！我會用身體擋住！！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L48_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_MAM","text":{"KOREA":"대장님…!","JPN":"隊長……！","ENG":"Captain...!","TWN":"隊長…！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_CAP","text":{"KOREA":"…쓰러졌어?","JPN":"……倒れた？","ENG":"...It's dead?","TWN":"…死掉了？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"방금 그 빛은…?","JPN":"さっきの光は……？","ENG":"What was that light...?","TWN":"剛剛那道光是…？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"하… 하아…","JPN":"はぁ……はあ……","ENG":"*Huff* *Huff*","TWN":"呼…呼…"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"저… 안 늦었죠?","JPN":"私……間に合いましたよね？","ENG":"I... wasn't too late, was I?","TWN":"我…沒來晚吧？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_MAM","text":{"KOREA":"……성자다.","JPN":"……聖者だ。","ENG":"...It's the Helgon.","TWN":"…是聖者。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_MAM","text":{"KOREA":"성자님이다!","JPN":"聖者様だ！","ENG":"It's the Helgon!","TWN":"是聖者！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L11_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_MAM","text":{"KOREA":"성자님이 돌아왔어!","JPN":"聖者様が戻ってきた！","ENG":"The Helgon is back!","TWN":"聖者回來了！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE_03"},{"id":"L13_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"루 양…? 정말로 살아 돌아온 겁니까?","JPN":"ルーさん……？　本当に生きて帰ってきたのですか？","ENG":"Ms. Lugh...? Is that really you?","TWN":"露…？你活著回來了？！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"그 괴물을 어떻게 따돌린 거죠?","JPN":"あの化け物をどうやって……？","ENG":"How did you manage to flee from that monster?","TWN":"你是怎麼甩掉那個怪物的？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"요정님을 만났거든요.","JPN":"妖精さんに会ったんです。","ENG":"I met a fairy.","TWN":"我遇到了精靈。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"요정이라…","JPN":"妖精ですか……","ENG":"A fairy...?","TWN":"精靈嗎…"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"믿기 힘들지만… 믿을 수밖에 없는 기적이군요.","JPN":"信じ難いですが……奇跡だとしか言いようがありませんね。","ENG":"It's hard to believe... but a miracle that I must.","TWN":"雖然難以置信…但這是個不得不信的奇蹟。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"모르가나는 어때요? 무사한가요?","JPN":"モルガナはどこです？　無事ですか？","ENG":"How is Morgana? Is she safe?","TWN":"莫甘娜怎麼樣？她還好嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"…낙원문이 완성되었습니다.","JPN":"……楽園の門が完成しました。","ENG":"...Avalon's Gate has been completed.","TWN":"…樂園門已經完成了。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"완벽한 준비가 아니었기에 모두를 보낼 수 없어서 소수를 선별해야만 했고, 모르가나 아가씨도 그 중 하나였죠.","JPN":"全員を送れるほどの準備ができなかったため、子どもたちを優先して送ることになりました。モルガナお嬢様もそのうちの一人です。","ENG":"However, preparations for the space jump were not perfect, and only a few people had to be chosen. Morgana was one of them.","TWN":"因為準備不夠充分，無法讓所有人透過，只能選擇少數人，小姐就是其中之一。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"잘 됐네요. 모르가나는 낙원으로 갈 자격이 있으니까요.","JPN":"よかったです。モルガナは楽園に行く資格がありますから。","ENG":"That's good news. Morgana deserves to go to the Promised Land.","TWN":"那就好，莫甘娜有資格前往樂園。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"죄송합니다. 우리 사람들을 살리기 위해 루 양을 이용한 꼴이 되었군요.","JPN":"申し訳ありません。みんなを助けるために、ルーさんを利用する形になってしまいました。","ENG":"I must apologize. It seems that I have used you to save our people.","TWN":"對不起。為了救我們的人，結果利用了露…"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"아뇨. 그런 말씀 마세요.","JPN":"いいえ。そんなこと言わないでください。","ENG":"No, don't say that.","TWN":"不，請別說這種話。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"마왕에게 맞서 사람들을 지키는 건, 제 평생의 목표였으니까요.","JPN":"魔王に立ち向かって人々を守るのは、私の使命でしたから。","ENG":"It has been my life goal to fight the Demon Lord and protect the people.","TWN":"對抗魔王，保護人們，是我一生的目標。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"그리고…","JPN":"それから……","ENG":"Also...","TWN":"還有…"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_CONFUSION"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"그루터기는 이제, 제가 돌아갈 집이기도 한 걸요?","JPN":"切り株は、私の家でもあるんですよ？","ENG":"the Stump is now my home, isn't it?","TWN":"木墩現在也是我回家的地方，不是嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"…고맙습니다.","JPN":"……ありがとうございます。","ENG":"...Thank you.","TWN":"…謝謝。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"루 양이 함께해준다면, 저희도 두려울 게 없지요.","JPN":"ルーさんが共にしてくれるなら、私たちも怖いものはありません。","ENG":"With you by our side, Ms. Lugh, we have nothing to fear.","TWN":"有露和我們一起，就什麼也不怕了。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_CAP","text":{"KOREA":"무기를 들어!","JPN":"武器を構えろ！","ENG":"Raise your weapons!","TWN":"拿起武器！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KEEPER_ROOT_NPC_CAP","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_CAP","text":{"KOREA":"이 세계 너머에서 새로운 역사를 이어갈 우리의 후손들을 위해…!","JPN":"この世界の向こうで新しい歴史を繋いでくれる我々の末裔のために……！","ENG":"For our descendants who will continue our legacy from this land beyond...!","TWN":"為了能夠在世界的另一端延續創造新歷史的後代…！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L39_1","type":"dialog","speaker":"KEEPER_ROOT_NPC_CAP","text":{"KOREA":"목숨을 걸고 여길 지키는 거다!!","JPN":"命をかけてここを守るんだ！！","ENG":"We fight here with our lives to protect this place!!","TWN":"拼命守住這裡！！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CA_HUNTRESS","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};